sys_ws_operation.operation_script:
(function process(request, response) {
      var token = request.queryParams.token;
      if (Array.isArray(token)) token = token[0];

      response.setContentType('text/html');

      if (!token) {
          return _html(response, 400, 'Token ausente', '<p>Link invalido (sem token).</p>');
      }

      var mlt = new x_1880990_chain.MagicLinkToken();
      var v = mlt.verify(token);
      if (!v.valid) {
          var msg = v.reason === 'expired' ? 'Este link expirou.' :
                    v.reason === 'invalid_signature' ? 'Link invalido (assinatura nao confere).' :
                    'Link invalido (' + v.reason + ').';
          return _html(response, 401, 'Link invalido', '<p>' + msg + '</p>');
      }

      if (v.payload.a !== 'counter') {
          return _html(response, 400, 'Acao invalida', '<p>Este link nao corresponde a acao de contraproposta.</p>');
      }

      var p = new GlideRecord('x_1880990_chain_proposal');
      if (!p.get(v.payload.p)) {
          return _html(response, 404, 'Proposta nao encontrada', '<p>A proposta deste link nao existe mais.</p>');
      }

      if (p.state.toString() !== '20') {
          return _html(response, 409, 'Estado invalido',
              '<p>A proposta nao esta mais aguardando sua decisao (estado atual: ' + p.state.toString() + ').</p>');
      }

      if (p.owner.toString() !== v.payload.o) {
          return _html(response, 403, 'Permissao negada', '<p>Voce nao e o proprietario desta proposta.</p>');
      }

      var instanceUri = gs.getProperty('glide.servlet.uri');
      var submitUrl = instanceUri + 'api/x_1880990_chain/chain_magic_link/counter_submit?token=' + encodeURIComponent(token);

      var form =
          '<div style="background: #fff8e1; padding: 24px; border-radius: 8px; text-align: left;">' +
          '<h3 style="margin-top: 0;">Detalhes da proposta</h3>' +
          '<p><strong>Veiculo:</strong> ' + p.car_name + ' - ' + p.car_brand + ' ' + p.car_model + ' ' + p.car_color + '</p>' +
          '<p><strong>Chassi:</strong> ' + p.car_chassi + '</p>' +
          '<p><strong>Comprador:</strong> ' + p.buyer.getDisplayValue() + '</p>' +
          '<p><strong>Valor FIPE:</strong> R$ ' + p.car_fipe_value + '</p>' +
          '<p><strong>Oferta atual do comprador:</strong> R$ ' + p.purchase_offer + '</p>' +
          '</div>' +
          '<form method="POST" action="' + submitUrl + '" style="margin-top: 24px;">' +
          '<label for="counter_offer" style="display: block; margin-bottom: 8px; font-weight: bold;">Sua contraproposta (R$):</label>' +
          '<input type="number" id="counter_offer" name="counter_offer" required min="1" step="0.01" ' +
          'style="width: 100%; padding: 12px; font-size: 1.1em; border: 1px solid #ccc; border-radius: 4px;" />' +
          '<button type="submit" ' +
          'style="margin-top: 16px; padding: 12px 24px; background: #f39c12; color: white; border: none; border-radius: 4px; font-size: 1em; cursor: pointer;">' +
          'Enviar contraproposta</button>' +
          '</form>';

      return _html(response, 200, 'Contraproposta - ' + p.number, form);

      function _html(response, status, title, body) {
          response.setStatus(status);
          var page =
              '<html><head><meta charset="utf-8"><title>' + title + '</title></head>' +
              '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 40px auto; padding: 0 20px;">' +
              '<h1 style="color: #2c3e50;">' + title + '</h1>' +
              body +  
              '<p style="color: #888; font-size: 12px; margin-top: 32px; text-align: center;">Chain Academy &mdash; Detran SP</p>' +
              '</body></html>';
          response.getStreamWriter().writeString(page);
      }
  })(request, response);
